css:
.input-underline-wrap { position: relative; padding-bottom: 4px; }
.input-underline-wrap input {
  width: 100%;
  background: transparent;
  border: none;
  border-bottom: 1px solid rgba(255,255,255,0.2);
  color: #fff;
  font-size: 15px;
  padding: 8px 0;
  outline: none;
}
.input-underline-wrap input::placeholder { color: rgba(255,255,255,0.35); }
.line {
  position: absolute;
  bottom: 4px; left: 0;
  height: 2px; width: 0;
  background: #B8FB3C;
  transition: width 0.3s ease;
}
.input-underline-wrap:focus-within .line { width: 100%; }

.float-label-wrap { position: relative; margin-top: 16px; }
.float-label-wrap input {
  width: 100%;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.15);
  border-radius: 8px;
  color: #fff;
  font-size: 15px;
  padding: 14px 16px 6px;
  outline: none;
  transition: border-color 0.2s ease;
}
.float-label-wrap input:focus { border-color: #B8FB3C; }
.float-label-wrap label {
  position: absolute;
  top: 50%; left: 16px;
  transform: translateY(-50%);
  color: rgba(255,255,255,0.4);
  font-size: 14px;
  pointer-events: none;
  transition: all 0.2s ease;
}
.float-label-wrap input:focus ~ label,
.float-label-wrap input:not(:placeholder-shown) ~ label {
  top: 8px; font-size: 11px; color: #B8FB3C;
}

.glass-input {
  background: rgba(255,255,255,0.08);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255,255,255,0.15);
  border-radius: 10px;
  padding: 10px 16px;
  color: #fff;
  font-size: 14px;
  width: 100%;
  outline: none;
  transition: all 0.2s ease;
}
.glass-input::placeholder { color: rgba(255,255,255,0.4); }
.glass-input:focus {
  border-color: rgba(255,255,255,0.4);
  background: rgba(255,255,255,0.12);
  box-shadow: 0 0 0 3px rgba(255,255,255,0.08);
}

.neon-input {
  background: rgba(0,0,0,0.5);
  border: 1px solid rgba(184,251,60,0.3);
  border-radius: 8px;
  padding: 10px 16px;
  color: #B8FB3C;
  font-size: 14px;
  width: 100%;
  outline: none;
  transition: all 0.3s ease;
  font-family: monospace;
}
.neon-input::placeholder { color: rgba(184,251,60,0.3); }
.neon-input:focus {
  border-color: #B8FB3C;
  box-shadow: 0 0 8px rgba(184,251,60,0.4), 0 0 20px rgba(184,251,60,0.1), inset 0 0 8px rgba(184,251,60,0.05);
}

.grad-border-wrap {
  padding: 1.5px;
  border-radius: 9px;
  background: linear-gradient(135deg, #B8FB3C, #a855f7, #06b6d4);
  background-size: 200% 200%;
  animation: grad-shift 3s ease infinite;
}
.grad-border-wrap input {
  background: #0a0a0f;
  border: none;
  border-radius: 8px;
  padding: 10px 16px;
  color: #fff;
  font-size: 14px;
  width: 100%;
  outline: none;
}
@keyframes grad-shift {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}

.search-wrap { position: relative; display: flex; align-items: center; }
.search-icon { position: absolute; left: 14px; width: 16px; height: 16px; color: rgba(255,255,255,0.35); pointer-events: none; }
.search-wrap input {
  width: 100%;
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 50px;
  padding: 10px 16px 10px 40px;
  color: #fff;
  font-size: 13px;
  outline: none;
  transition: all 0.2s ease;
}
.search-wrap input::placeholder { color: rgba(255,255,255,0.3); }
.search-wrap input:focus { border-color: rgba(255,255,255,0.3); }

.otp-wrap { display: flex; gap: 8px; }
.otp-box {
  width: 44px; height: 52px;
  text-align: center;
  font-size: 18px;
  font-weight: 700;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 10px;
  color: #fff;
  outline: none;
  caret-color: #B8FB3C;
  transition: all 0.2s ease;
}
.otp-box:focus {
  border-color: #B8FB3C;
  background: rgba(184,251,60,0.05);
  box-shadow: 0 0 0 3px rgba(184,251,60,0.15);
}

.dark-input {
  background: #1a1a2e;
  border: 1px solid #2d2d4e;
  border-radius: 8px;
  padding: 10px 16px;
  color: #e2e8f0;
  font-size: 14px;
  width: 100%;
  outline: none;
  transition: all 0.2s ease;
}
.dark-input::placeholder { color: #4a4a6a; }
.dark-input:focus { border-color: #6366f1; box-shadow: 0 0 0 3px rgba(99,102,241,0.15); }

.pill-input {
  background: rgba(255,255,255,0.07);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 50px;
  padding: 10px 20px;
  color: #fff;
  font-size: 14px;
  width: 100%;
  outline: none;
  transition: all 0.2s ease;
}
.pill-input::placeholder { color: rgba(255,255,255,0.35); }
.pill-input:focus { border-color: rgba(255,255,255,0.3); }

.styled-textarea {
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 12px;
  padding: 12px 16px;
  color: #fff;
  font-size: 14px;
  width: 100%;
  resize: vertical;
  outline: none;
  line-height: 1.6;
  font-family: inherit;
  transition: all 0.2s ease;
}
.styled-textarea::placeholder { color: rgba(255,255,255,0.3); }
.styled-textarea:focus { border-color: rgba(255,255,255,0.25); background: rgba(255,255,255,0.07); }

.custom-checkbox {
  display: flex;
  align-items: center;
  gap: 10px;
  cursor: pointer;
  color: rgba(255,255,255,0.7);
  font-size: 14px;
  user-select: none;
}
.custom-checkbox input { display: none; }
.checkmark {
  width: 20px; height: 20px;
  border-radius: 5px;
  border: 1px solid rgba(255,255,255,0.2);
  background: rgba(255,255,255,0.05);
  display: flex; align-items: center; justify-content: center;
  transition: all 0.2s ease;
  flex-shrink: 0;
}
.custom-checkbox input:checked ~ .checkmark {
  background: #B8FB3C;
  border-color: #B8FB3C;
}
.custom-checkbox input:checked ~ .checkmark::after {
  content: '';
  width: 5px; height: 9px;
  border: 2px solid #0a0a0f;
  border-top: none; border-left: none;
  transform: rotate(45deg) translateY(-1px);
}

.toggle-switch { position: relative; display: inline-block; width: 48px; height: 26px; cursor: pointer; }
.toggle-switch input { display: none; }
.slider {
  position: absolute; inset: 0;
  background: rgba(255,255,255,0.1);
  border-radius: 50px;
  border: 1px solid rgba(255,255,255,0.15);
  transition: all 0.3s ease;
}
.slider::before {
  content: '';
  position: absolute;
  width: 18px; height: 18px;
  left: 3px; top: 3px;
  background: rgba(255,255,255,0.6);
  border-radius: 50%;
  transition: all 0.3s cubic-bezier(0.34,1.56,0.64,1);
}
.toggle-switch input:checked ~ .slider { background: #B8FB3C; border-color: #B8FB3C; }
.toggle-switch input:checked ~ .slider::before { background: #0a0a0f; transform: translateX(22px); }

.custom-range {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 4px;
  border-radius: 2px;
  background: rgba(255,255,255,0.1);
  outline: none;
  cursor: pointer;
}
.custom-range::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 18px; height: 18px;
  border-radius: 50%;
  background: #B8FB3C;
  border: 2px solid #0a0a0f;
  box-shadow: 0 0 0 3px rgba(184,251,60,0.2);
  transition: all 0.2s ease;
}
.custom-range::-webkit-slider-thumb:hover { box-shadow: 0 0 0 6px rgba(184,251,60,0.2); }

.select-wrap { position: relative; display: inline-block; width: 100%; }
.custom-select {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 8px;
  padding: 10px 36px 10px 14px;
  color: #fff;
  font-size: 14px;
  outline: none;
  cursor: pointer;
  transition: all 0.2s ease;
}
.custom-select:focus { border-color: rgba(255,255,255,0.3); }
.select-wrap::after { content: '▾'; position: absolute; right: 14px; top: 50%; transform: translateY(-50%); color: rgba(255,255,255,0.4); pointer-events: none; font-size: 12px; }

.file-upload {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  width: 100%;
  padding: 24px;
  border: 2px dashed rgba(255,255,255,0.15);
  border-radius: 12px;
  cursor: pointer;
  color: rgba(255,255,255,0.5);
  font-size: 13px;
  transition: all 0.2s ease;
  text-align: center;
}
.file-upload .icon { font-size: 24px; }
.file-upload:hover { border-color: #B8FB3C; background: rgba(184,251,60,0.04); color: rgba(255,255,255,0.7); }
